import { useState } from "react";

export default function SubmitBug() {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [severity, setSeverity] = useState("low");
  const [message, setMessage] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage("");

    const token = localStorage.getItem("token");

    try {
      const res = await fetch("http://localhost:5000/api/bugs", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({
          title,
          description,
          severity,
        }),
      });

      const data = await res.json();

      if (!res.ok) {
        setMessage(data.msg || "Something went wrong");
        return;
      }

      setMessage("✅ Bug submitted successfully!");
      setTitle("");
      setDescription("");
      setSeverity("low");
    } catch (err) {
      setMessage("❌ Server error");
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 p-8">
      <div className="max-w-xl mx-auto bg-white p-6 rounded shadow">
        <h2 className="text-2xl font-bold mb-4">🐞 Submit Bug</h2>

        {message && <p className="mb-4">{message}</p>}

        <form onSubmit={handleSubmit}>
          <label className="block mb-2">Title</label>
          <input
            className="w-full border p-2 rounded mb-4"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            required
          />

          <label className="block mb-2">Description</label>
          <textarea
            className="w-full border p-2 rounded mb-4"
            rows="4"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            required
          />

          <label className="block mb-2">Severity</label>
          <select
            className="w-full border p-2 rounded mb-4"
            value={severity}
            onChange={(e) => setSeverity(e.target.value)}
          >
            <option value="low">Low</option>
            <option value="medium">Medium</option>
            <option value="high">High</option>
            <option value="critical">Critical</option>
          </select>

          <button className="w-full bg-blue-600 text-white p-2 rounded">
            Submit Bug
          </button>
        </form>
      </div>
    </div>
  );
}
